export type TruncateOptions = { ellipsis?: string };

/**
 * Truncate a string by replacing its middle with an ellipsis (or custom marker) so the result length <= maxLength.
 *
 * See SPEC.md for full specification and examples.
 */
export function truncateMiddle(text: string, maxLength: number, options?: TruncateOptions): string {
  const ellipsis = options?.ellipsis ?? "…"; // default single-character ellipsis

  if (!Number.isFinite(maxLength) || Math.floor(maxLength) !== maxLength) {
    throw new RangeError("maxLength must be a finite integer");
  }
  if (maxLength < 0) {
    throw new RangeError("maxLength must be >= 0");
  }

  // Quick path: nothing to do
  if (text.length <= maxLength) return text;

  if (maxLength === 0) return "";

  const ellLen = ellipsis.length;

  // If maxLength is smaller than the ellipsis, return truncated ellipsis
  if (maxLength <= ellLen) {
    return ellipsis.slice(0, maxLength);
  }

  const available = maxLength - ellLen;
  const startLen = Math.ceil(available / 2);
  const endLen = Math.floor(available / 2);

  const start = text.slice(0, startLen);
  const end = text.slice(text.length - endLen);

  return start + ellipsis + end;
}

export default truncateMiddle;

import { describe, it, expect } from 'vitest'
import { truncateMiddle } from '../src/index'

describe('truncateMiddle', () => {
  it('returns the original text when shorter than maxLength', () => {
    expect(truncateMiddle('Hello', 10)).toBe('Hello')
  })

  it('truncates typical long string with default ellipsis', () => {
    const input = 'The quick brown fox jumps over the lazy dog'
    const out = truncateMiddle(input, 15)
    // should be length 15
    expect(out.length).toBeLessThanOrEqual(15)
    // should contain ellipsis
    expect(out).toContain('…')
    // prefix and suffix preserved
    expect(out.startsWith('The qui')).toBe(true)
    expect(out.endsWith('y dog')).toBe(true)
  })

  it('returns ellipsis when maxLength equals ellipsis length', () => {
    expect(truncateMiddle('abcdef', 1)).toBe('…')
  })

  it('returns truncated ellipsis when maxLength < ellipsis length', () => {
    expect(truncateMiddle('abcdef', 2, { ellipsis: '[...]' })).toBe('[.')
  })

  it('returns empty string when maxLength is 0', () => {
    expect(truncateMiddle('anything', 0)).toBe('')
  })

  it('throws RangeError for negative maxLength', () => {
    expect(() => truncateMiddle('x', -1)).toThrow(RangeError)
  })

  it('allocates extra char to start when available is odd', () => {
    // available = maxLength - ellLen
    // for this test: maxLength=6, ellLen=1 => available=5 => start=3 end=2
    const s = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'
    const out = truncateMiddle(s, 6)
    // start should have 3 chars
    expect(out.slice(0, 3)).toBe(s.slice(0, 3))
    // end should have 2 chars
    expect(out.slice(-2)).toBe(s.slice(-2))
  })
})
